const lead = $input.first().json;

// Nettoyer les notes
const cleanedNotes = (lead.Notes || '')
  .replace(/\n/g, ' ')
  .replace(/\r/g, '')
  .replace(/\t/g, ' ')
  .replace(/"/g, '\\"')
  .replace(/\\/g, '\\\\')
  .trim();

return {
  name: lead['Nom Contact'],
  poste: lead.Poste,
  statut: lead.Statut,
  nextStep: lead['Next Step'],
  interet: lead['Intérêt'],
  dateProchainMessage: lead['Date Prochain Message']?.start,
  notes: cleanedNotes
};

const tasks = $input.first().json.tasks;
const targetTitle = $('Format').first().json.title;

const foundTask = tasks.find(task => task.title === targetTitle);

return foundTask ? {id: foundTask.id} : {id: null};

// Déclaration des constantes
const TRAVAIL_PROJECT_ID = '66ba4bbedb643ca0adb34ab0';
const value = $('Mapping').first().json;
const output = $input.first().json.output;

// Format content
const content = `
Message suggéré:

${output.message}

---

Notes:

${value.notes}
`;

return {
  projectId: TRAVAIL_PROJECT_ID,
  title: `${output.title}: ${value.name}`,
  content: content.trim(),
  startDate: `${value.dateProchainMessage}`,
  tags: ["🤖Auto", "🕒-5mn"],
};

